      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        DEFAULT_ENTRY: sMATHS_VALUE, 
        BELOW: SDAI.INTEGER, 
        ABOVE: SDAI.INTEGER, 
        ORDER: nORDERING_TYPE
      ) {

        self._default_entry = DEFAULT_ENTRY
        self._below = BELOW
        self._above = ABOVE
        self._order = ORDER

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( DEFAULT_ENTRY: original._default_entry, BELOW: original._below, ABOVE: original._above, ORDER: original._order )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 4
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: sMATHS_VALUE.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]DEFAULT_ENTRY for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: SDAI.INTEGER.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]BELOW for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: SDAI.INTEGER.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]ABOVE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverRequiredParameter(as: nORDERING_TYPE.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]ORDER for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( DEFAULT_ENTRY: p0, BELOW: p1, ABOVE: p2, ORDER: p3 )
      }
    }
  }
}
